import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'When clicking \'Test workflow\'' },
});

const waitNode = node({
  type: 'n8n-nodes-base.wait',
  version: 1.1,
  config: {
    name: 'Wait',
    parameters: {
      resume: 'timeInterval',
      amount: 1,
      unit: 'seconds',
    },
  },
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'running state test',
    parameters: {
      mode: 'manual',
      assignments: { assignments: [] },
    },
  },
});

export default workflow('id', 'Running State Test')
  .add(manualTrigger)
  .to(waitNode)
  .to(setNode);
